  tmuxPanes(filter: {paneIdIn: $paneIds}) {
    ...PaneCard
    id
  }
  claudeInstances {
    ...SessionCard
    id
  }
  conversations {
    sessionUuid
    lastSeenAt
    firstSeenAt
    messageCount
    open
    recap
    cwd
    jsonlPath
    agentName
    customTitle
    id
  }
  workView {
    repos {
      id
      slug
      worktrees {
        ...WorktreeEnrichment
        id
      }
    }
  }
}

